    if (next.pseudo && !beta124IsGuestPseudo(next.pseudo)) BETA124_PSEUDO_KEYS.forEach(key => beta124LocalSet(key, next.pseudo));
    localStorage.setItem(BETA124_IDENTITY_KEY, JSON.stringify(next));
