  if (identity.friendCode) BETA124_FRIEND_CODE_KEYS.forEach(key => beta124LocalSet(key, identity.friendCode));
  if (identity.pseudo) BETA124_PSEUDO_KEYS.forEach(key => beta124LocalSet(key, identity.pseudo));
